#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""装饰器示例"""

def simple_decorator(func):
    """最简单的装饰器"""
    def wrapper():
        print("函数执行前")
        func()
        print("函数执行后")
    return wrapper

@simple_decorator
def say_hello():
    print("Hello!")

# 使用装饰器
say_hello()

# 输出：
# 函数执行前
# Hello!
# 函数执行后

